DROP TABLE IF EXISTS `ea_whatsapp_excutions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ea_whatsapp_excutions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `whatsapp_signal_id` bigint unsigned NOT NULL,
  `account_id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('received','executed','failed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'received',
  `executed_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ea_whatsapp_excutions_whatsapp_signal_id_foreign` (`whatsapp_signal_id`),
  CONSTRAINT `ea_whatsapp_excutions_whatsapp_signal_id_foreign` FOREIGN KEY (`whatsapp_signal_id`) REFERENCES `whatsapp_signals` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=955 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

