DROP TABLE IF EXISTS `signal_accounts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `signal_accounts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `signal_id` bigint unsigned NOT NULL,
  `account_id` bigint unsigned NOT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `ticket` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `signal_accounts_signal_id_foreign` (`signal_id`),
  KEY `signal_accounts_account_id_foreign` (`account_id`),
  CONSTRAINT `signal_accounts_account_id_foreign` FOREIGN KEY (`account_id`) REFERENCES `accounts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `signal_accounts_signal_id_foreign` FOREIGN KEY (`signal_id`) REFERENCES `signals` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1280 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
